// services/database.ts

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export async function createWorkProfile(profileData: any) {
  const { data, error } = await supabase
    .from('work_profiles')
    .insert([profileData]);

  if (error) {
    console.error('Error creating work profile:', error);
    return null;
  }
  return data;
}

export async function updateWorkProfile(profileId: string, updatedProfileData: any) {
  const { data, error } = await supabase
    .from('work_profiles')
    .update(updatedProfileData)
    .match({ id: profileId });

  if (error) {
    console.error('Error updating work profile:', error);
    return null;
  }
  return data;
}

export async function fetchWorkProfiles() {
  const { data, error } = await supabase
    .from('work_profiles')
    .select('*');

  if (error) {
    console.error('Error fetching work profiles:', error);
    return null;
  }
  return data;
}

